from __future__ import annotations

from ..formal_model import FormalModel, ModelResult


def formal_model_markdown(model: FormalModel, result: ModelResult) -> str:
    lines = [
        "# Bounded Lifecycle Model",
        "",
        "> Generated by `./hfx generate`. Do not edit manually.",
        "",
        "This state explorer is independent of the Rust production state machines.",
        "It exhaustively checks the reviewed finite lease, generation, transaction, delivery, and stable-intent model.",
        "It does not substitute for physical receiver evidence.",
        "",
        "## Completed Exploration",
        "",
        f"- States: `{result.states}`",
        f"- Transition edges: `{result.transitions}`",
        f"- Maximum depth reached: `{result.maximum_depth_reached}`",
        f"- State bound: `{model.maximum_states}`",
        "",
        "## Covered Transitions",
        "",
    ]
    lines.extend(f"- `{name}`" for name in result.transition_names)
    lines.extend(["", "## Checked Invariants", ""])
    lines.extend(f"- `{invariant}`" for invariant in model.invariant_ids)
    lines.append("")
    return "\n".join(lines)
